export const 璇璣八卦圖 = (bi) => {
    const u = bi.u, k = 2.4;
    const X = (c) => (c - 5.0) * k;
    const Z = (r) => (r - 3.9) * k + 3;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.4) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    const 圈 = (x, z, r = 0.2) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.35 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    const 爻 = (a, b) => 線(p => p.M(X(a[0]), Z(a[1])).L(X(b[0]), Z(b[1])), 0.6);
    // 輪上人字圈鏈（左端曲收・頂圈・右垂漸沒）
    出(p => p.M(X(6.55), Z(4.35))
        .C(X(5.3), Z(4.7), X(4.1), Z(5.0), X(3.1), Z(5.25))
        .C(X(2.9), Z(5.3), X(2.85), Z(5.15), X(2.95), Z(5.0)), 0.36);
    圈(6.83, 4.22);
    出(p => p.M(X(7.1), Z(4.35)).C(X(7.7), Z(4.5), X(8.3), Z(4.65), X(8.77), Z(4.82)), 0.36);
    // 上卦・離☲（陽・陰・陽）
    爻([5.93, 5.44], [7.79, 5.44]);
    爻([5.96, 5.93], [6.67, 5.93]);
    爻([7.01, 5.93], [7.79, 5.93]);
    爻([5.93, 6.42], [7.82, 6.42]);
    // 圓輪：上緣點斷三段
    線(p => p.M(X(4.5), Z(7.6)).C(X(4.76), Z(7.44), X(5.03), Z(7.28), X(5.3), Z(7.15)), 0.3);
    線(p => p.M(X(6.2), Z(7.0)).C(X(6.47), Z(7.04), X(6.74), Z(7.1), X(7.0), Z(7.15)), 0.3);
    線(p => p.M(X(7.8), Z(7.5)).C(X(8.0), Z(7.64), X(8.2), Z(7.8), X(8.4), Z(7.95)), 0.3);
    // 左緣長弧
    線(p => p.M(X(3.5), Z(8.3))
        .C(X(2.8), Z(9.2), X(2.55), Z(10.4), X(2.7), Z(11.4))
        .C(X(2.85), Z(12.6), X(3.15), Z(13.7), X(3.6), Z(14.6)), 0.34);
    // 下緣弧（至坎前收）
    線(p => p.M(X(3.6), Z(14.6))
        .C(X(4.1), Z(15.3), X(4.7), Z(15.7), X(5.4), Z(15.8)), 0.34);
    // 右下漫漶殘段
    線(p => p.M(X(8.2), Z(15.0)).C(X(8.45), Z(14.86), X(8.68), Z(14.7), X(8.9), Z(14.55)), 0.3);
    // 左卦・震☳（初爻朝外：外陽・中陰・上陰）
    爻([1.21, 10.2], [1.21, 12.2]);
    爻([1.7, 10.25], [1.7, 11.05]);
    爻([1.7, 11.4], [1.7, 12.15]);
    爻([2.16, 10.25], [2.16, 11.05]);
    爻([2.16, 11.35], [2.16, 12.15]);
    // 上左卦・巽☴（外陰・中陽・內陽）
    爻([2.16, 7.8], [2.84, 7.12]);
    爻([3.0, 7.0], [3.52, 6.36]);
    爻([2.52, 8.08], [3.84, 6.76]);
    爻([2.72, 8.4], [4.16, 7.0]);
    // 下左卦・艮☶（外陰・中陰・內陽）
    爻([2.14, 14.59], [2.75, 15.16]);
    爻([2.86, 15.35], [3.5, 15.98]);
    爻([2.45, 14.27], [3.12, 14.87]);
    爻([3.3, 15.03], [3.98, 15.65]);
    爻([2.79, 13.99], [3.83, 14.89]);
    // 下卦・坎☵（陰・陽・陰）
    爻([5.93, 15.65], [6.76, 15.65]);
    爻([7.04, 15.65], [7.94, 15.65]);
    爻([6.0, 16.2], [7.89, 16.2]);
    爻([5.96, 16.75], [6.76, 16.75]);
    爻([7.04, 16.75], [7.84, 16.75]);
    // 輪內璇璣星鏈（圈四・鉤一・末芒右出）
    圈(3.43, 10.34);
    圈(5.18, 10.31);
    圈(7.55, 12.2);
    圈(3.24, 12.4);
    連([3.43, 10.34], [5.18, 10.31]);
    連([3.43, 10.34], [3.24, 12.4]);
    // B→折鉤 C（直垂微斜，鉤處小曲，無圈）
    線(p => p.M(X(5.28), Z(10.62)).L(X(5.62), Z(11.95))
        .C(X(5.68), Z(12.18), X(5.8), Z(12.26), X(5.98), Z(12.22)), 0.36);
    線(p => p.M(X(6.0), Z(12.21)).L(X(7.2), Z(12.2)), 0.36);
    // D→右上芒（漸沒）
    出(p => p.M(X(7.8), Z(12.05)).C(X(8.2), Z(11.8), X(8.6), Z(11.5), X(8.97), Z(11.27)), 0.38);
};
